-- Acts 23 — The Lord Stands By: From Sanhedrin to Caesarea
-- Theme: Heaven's Courage Against the Conspirators

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 23,
  'Acts 23 carries Paul from the Antonia Fortress into the Sanhedrin and out to Caesarea under Roman military escort. Paul opens before the council with a clear conscience and is struck on the mouth by order of the high priest Ananias — whom he rebukes as a "whited wall" until told of the man''s office. Sensing the council''s mixed composition, Paul raises the flag of resurrection: "I am a Pharisee, the son of a Pharisee; of the hope and resurrection of the dead I am called in question." The body splinters — Pharisees now find themselves almost defending him, Sadducees raging against; Lysias must again rescue Paul from being torn in pieces. That night the Lord Himself stands by Paul: "Be of good cheer, Paul, for as thou hast testified of me in Jerusalem, so must thou bear witness also at Rome." On the morrow more than forty Jewish zealots swear an oath under cherem — no food or drink until Paul dies — but Paul''s nephew, overhearing, warns Lysias. The tribune mobilises a stunning escort of 470 men (200 infantry, 70 cavalry, 200 spearmen) to spirit Paul by night to Caesarea, enclosing him in a carefully worded letter to the governor Antonius Felix. By morning Paul is delivered in Herod''s praetorium, and Felix orders him kept there until his accusers arrive.',
  'Heaven''s Courage Against the Conspirators',
  'θάρσει',
  'be of good cheer, take courage (tharsei) — the Lord''s word to Paul in v.11, sealing his journey to Rome.',
  '[{"range":"vv.1-5","title":"Struck by the High Priest: ''Whited Wall''"},{"range":"vv.6-10","title":"The Pharisee-Sadducee Split Over Resurrection"},{"range":"v.11","title":"The Night Vision: ''As Thou Hast Testified... So Also at Rome''"},{"range":"vv.12-15","title":"The Forty-Man Oath Under Cherem"},{"range":"vv.16-22","title":"The Nephew''s Warning"},{"range":"vv.23-30","title":"The Military Escort and Lysias''s Letter"},{"range":"vv.31-35","title":"Antipatris, Caesarea, and Herod''s Praetorium"}]'::jsonb
FROM books b WHERE b.name = 'Acts'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  overview = EXCLUDED.overview,
  theme = EXCLUDED.theme,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And Paul, earnestly beholding the council, said, Men and brethren, I have lived in all good conscience before God until this day.',
      'Ἀτενίσας δὲ ὁ Παῦλος τῷ συνεδρίῳ εἶπεν, Ἄνδρες ἀδελφοί, ἐγὼ πάσῃ συνειδήσει ἀγαθῇ πεπολίτευμαι τῷ Θεῷ ἄχρι ταύτης τῆς ἡμέρας.',
      'Atenisas de ho Paulos tō synedriō eipen, Andres adelphoi, egō pasē syneidēsei agathē pepoliteumai tō Theō achri tautēs tēs hēmeras.',
      'Atenisas ("earnestly beholding") — Paul''s unflinching gaze (cf. 13:9). Pepoliteumai ("I have conducted my citizenship") is political vocabulary: Paul has lived as a citizen of God''s kingdom with clear conscience.',
      'A clear conscience before God is the Christian''s first credential in every court. Integrity of conscience stands when human verdicts fall.'),
  (2, 'And the high priest Ananias commanded them that stood by him to smite him on the mouth.',
      'Ὁ δὲ ἀρχιερεὺς Ἀνανίας ἐπέταξε τοῖς παρεστῶσιν αὐτῷ τύπτειν αὐτοῦ τὸ στόμα.',
      'Ho de archiereus Ananias epetaxe tois parestōsin autō typtein autou to stoma.',
      'Ananias son of Nedebaeus (high priest AD 47-59), notorious for greed and violence (Josephus, Ant. 20.9.2). He was assassinated by Zealots in AD 66 for Roman collaboration.',
      'Corrupt religious office does not muffle the voice of truth. The blow that silences the prophet''s mouth only amplifies his testimony.'),
  (3, 'Then said Paul unto him, God shall smite thee, thou whited wall: for sittest thou to judge me after the law, and commandest me to be smitten contrary to the law?',
      'τότε ὁ Παῦλος πρὸς αὐτὸν εἶπε, Τύπτειν σε μέλλει ὁ Θεός, τοῖχε κεκονιαμένε· καὶ σὺ κάθῃ κρίνων με κατὰ τὸν νόμον, καὶ παρανομῶν κελεύεις με τύπτεσθαι;',
      'tote ho Paulos pros auton eipe, Typtein se mellei ho Theos, toiche kekoniamene; kai sy kathē krinōn me kata ton nomon, kai paranomōn keleueis me typtesthai?',
      '"Whited wall" (toiche kekoniamene) echoes Ezek 13:10-15 — painted façade hiding rottenness. The prophecy came true: Ananias died violently at rebels'' hands in AD 66. Deut 25:1-2 forbids striking the uncondemned.',
      'Prophetic severity is not un-Christian. The apostle''s indictment of lawless judges echoes the prophets; God''s servants may still call out the painted tomb.'),
  (4, 'And they that stood by said, Revilest thou God''s high priest?',
      'Οἱ δὲ παρεστῶτες εἶπον, Τὸν ἀρχιερέα τοῦ Θεοῦ λοιδορεῖς;',
      'Hoi de parestōtes eipon, Ton archierea tou Theou loidoreis?',
      'The bystanders'' challenge presupposes respect for the office even when the man is unworthy.',
      'Office carries weight even when its holder fails. Honour attaches to the seat of authority by divine ordinance, not merely personal merit.'),
  (5, 'Then said Paul, I wist not, brethren, that he was the high priest: for it is written, Thou shalt not speak evil of the ruler of thy people.',
      'ἔφη τε ὁ Παῦλος, Οὐκ ᾔδειν, ἀδελφοί, ὅτι ἐστὶν ἀρχιερεύς· γέγραπται γάρ, Ἄρχοντα τοῦ λαοῦ σου οὐκ ἐρεῖς κακῶς.',
      'ephē te ho Paulos, Ouk ēdein, adelphoi, hoti estin archiereus; gegraptai gar, Archonta tou laou sou ouk ereis kakōs.',
      'Various explanations: Paul''s weak eyesight (Gal 4:15); Ananias not in full vestments; or (Calvin) irony meaning "I did not recognize him as acting like one." Paul''s immediate citation of Exod 22:28 shows genuine submission to Scripture.',
      'Scripture corrects even an inspired apostle''s zeal. The word of God governs the servant''s tongue no less than his theology.'),
  (6, 'But when Paul perceived that the one part were Sadducees, and the other Pharisees, he cried out in the council, Men and brethren, I am a Pharisee, the son of a Pharisee: of the hope and resurrection of the dead I am called in question.',
      'Γνοὺς δὲ ὁ Παῦλος ὅτι τὸ ἓν μέρος ἐστὶ Σαδδουκαίων, τὸ δὲ ἕτερον Φαρισαίων, ἔκραξεν ἐν τῷ συνεδρίῳ, Ἄνδρες ἀδελφοί, ἐγὼ Φαρισαῖός εἰμι, υἱὸς Φαρισαίου· περὶ ἐλπίδος καὶ ἀναστάσεως νεκρῶν ἐγὼ κρίνομαι.',
      'Gnous de ho Paulos hoti to hen meros esti Saddoukaiōn, to de heteron Pharisaiōn, ekraxen en tō synedriō, Andres adelphoi, egō Pharisaios eimi, huios Pharisaiou; peri elpidos kai anastaseōs nekrōn egō krinomai.',
      'A tactically brilliant move. Paul reframes the trial from "apostate" to "resurrection-hoper," exposing the Sanhedrin''s internal fault-line. The gospel crisis is finally the resurrection of Christ (cf. 2 Tim 2:8).',
      'At its deepest, the dispute over Christianity is a dispute over resurrection. If the dead rise, Christ rose and is Lord; if not, the church is to be pitied above all men.'),
  (7, 'And when he had so said, there arose a dissension between the Pharisees and the Sadducees: and the multitude was divided.',
      'Τοῦτο δὲ αὐτοῦ λαλήσαντος, ἐγένετο στάσις τῶν Φαρισαίων καὶ τῶν Σαδδουκαίων, καὶ ἐσχίσθη τὸ πλῆθος.',
      'Touto de autou lalēsantos, egeneto stasis tōn Pharisaiōn kai tōn Saddoukaiōn, kai eschisthē to plēthos.',
      'Stasis — faction, uprising. Long-standing theological differences erupt on the council floor.',
      'Unholy alliances fracture along their fault-lines under gospel pressure. The truth of Christ disturbs every false unity.'),
  (8, 'For the Sadducees say that there is no resurrection, neither angel, nor spirit: but the Pharisees confess both.',
      'Σαδδουκαῖοι μὲν γὰρ λέγουσι μὴ εἶναι ἀνάστασιν, μηδὲ ἄγγελον, μήτε πνεῦμα· Φαρισαῖοι δὲ ὁμολογοῦσι τὰ ἀμφότερα.',
      'Saddoukaioi men gar legousi mē einai anastasin, mēde angelon, mēte pneuma; Pharisaioi de homologousi ta amphotera.',
      'Luke parenthetically explains — the Sadducees denied resurrection, angels, and disembodied spirits (cf. Matt 22:23; Mark 12:18). Pharisaic belief, though often wrong on details, preserved these biblical truths.',
      'Doctrinal denial robs the living of hope and the dead of dignity. The gospel restores what sceptical religion empties.'),
  (9, 'And there arose a great cry: and the scribes that were of the Pharisees'' part arose, and strove, saying, We find no evil in this man: but if a spirit or an angel hath spoken to him, let us not fight against God.',
      'ἐγένετο δὲ κραυγὴ μεγάλη· καὶ ἀναστάντες οἱ γραμματεῖς τοῦ μέρους τῶν Φαρισαίων διεμάχοντο λέγοντες, Οὐδὲν κακὸν εὑρίσκομεν ἐν τῷ ἀνθρώπῳ τούτῳ· εἰ δὲ πνεῦμα ἐλάλησεν αὐτῷ ἢ ἄγγελος, μὴ θεομαχῶμεν.',
      'egeneto de kraugē megalē; kai anastantes hoi grammateis tou merous tōn Pharisaiōn diemachonto legontes, Ouden kakon heuriskomen en tō anthrōpō toutō; ei de pneuma elalēsen autō ē angelos, mē theomachōmen.',
      '"Let us not fight against God" (mē theomachōmen) echoes Gamaliel''s counsel in 5:39. The Pharisee scribes, startled by Paul''s Damascus-road report, cautiously credit the possibility of divine revelation.',
      'The fear of fighting against God is a restraining grace even among imperfect theologians. Gamaliel''s pupil has now provoked Gamaliel''s own party to the edge of right action.'),
  (10, 'And when there arose a great dissension, the chief captain, fearing lest Paul should have been pulled in pieces of them, commanded the soldiers to go down, and to take him by force from among them, and to bring him into the castle.',
      'Πολλῆς δὲ γενομένης στάσεως, εὐλαβηθεὶς ὁ χιλίαρχος μὴ διασπασθῇ ὁ Παῦλος ὑπ᾽ αὐτῶν, ἐκέλευσε τὸ στράτευμα καταβῆναι, καὶ ἁρπάσαι αὐτὸν ἐκ μέσου αὐτῶν, ἄγειν τε εἰς τὴν παρεμβολήν.',
      'Pollēs de genomenēs staseōs, eulabētheis ho chiliarchos mē diaspasthē ho Paulos hyp autōn, ekeleuse to strateuma katabēnai, kai harpasai auton ek mesou autōn, agein te eis tēn parembolēn.',
      'Lysias rescues Paul for the second time (cf. 21:31-32). Paul''s safety now lies literally in Roman hands.',
      'Providence repeatedly employs pagan powers to preserve God''s servant. The same empire that will behead Paul now saves him to write more letters.'),
  (11, 'And the night following the Lord stood by him, and said, Be of good cheer, Paul: for as thou hast testified of me in Jerusalem, so must thou bear witness also at Rome.',
      'Τῇ δὲ ἐπιούσῃ νυκτὶ ἐπιστὰς αὐτῷ ὁ Κύριος εἶπε, Θάρσει Παῦλε· ὡς γὰρ διεμαρτύρω τὰ περὶ ἐμοῦ εἰς Ἱερουσαλήμ, οὕτω σε δεῖ καὶ εἰς Ῥώμην μαρτυρῆσαι.',
      'Tē de epiousē nykti epistas autō ho Kyrios eipe, Tharsei Paule; hōs gar diemartyrō ta peri emou eis Ierousalēm, houtō se dei kai eis Rhōmēn martyrēsai.',
      'The sixth recorded appearance of the risen Christ to Paul (cf. 9:5; 18:9; 22:17-21; 26:16-18; 27:23-24). "Be of good cheer" (tharsei) is a Jesus-word from the Gospels (Matt 9:2; 14:27; John 16:33). Dei ("must") marks divine necessity.',
      'The risen Christ personally comforts His fearful apostles at midnight. Rome is not the servant''s prison but the Lord''s pulpit.'),
  (12, 'And when it was day, certain of the Jews banded together, and bound themselves under a curse, saying that they would neither eat nor drink till they had killed Paul.',
      'Γενομένης δὲ ἡμέρας, ποιήσαντές τινες τῶν Ἰουδαίων συστροφήν, ἀνεθεμάτισαν ἑαυτούς, λέγοντες μήτε φαγεῖν μήτε πιεῖν ἕως οὗ ἀποκτείνωσι τὸν Παῦλον.',
      'Genomenēs de hēmeras, poiēsantes tines tōn Ioudaiōn systrophēn, anethematisan heautous, legontes mēte phagein mēte piein heōs hou apokteinōsi ton Paulon.',
      'Anathematizein — to place under a cherem (devotion to destruction). This was the fiercest religious oath; rabbinic law released the oath-taker if fulfilment became impossible.',
      'Religious zeal, severed from truth, plots murder in the name of God. The fiercest oath can become the darkest sin when aimed at the Lord''s servant.'),
  (13, 'And they were more than forty which had made this conspiracy.',
      'Ἦσαν δὲ πλείους τεσσαράκοντα οἱ ταύτην τὴν συνωμοσίαν πεποιηκότες·',
      'Ēsan de pleious tessarakonta hoi tautēn tēn synōmosian pepoiēkotes;',
      '"More than forty" suggests a para-military cadre, probably Sicarii-affiliated. This is organized terrorism, not mob action.',
      'Organised malice cannot thwart divine providence. Forty conspirators cannot outnumber the One who keeps His servant through the night.'),
  (14, 'And they came to the chief priests and elders, and said, We have bound ourselves under a great curse, that we will eat nothing until we have slain Paul.',
      'οἵτινες προσελθόντες τοῖς ἀρχιερεῦσι καὶ τοῖς πρεσβυτέροις εἶπον, Ἀναθέματι ἀνεθεματίσαμεν ἑαυτούς, μηδενὸς γεύσασθαι ἕως οὗ ἀποκτείνωμεν τὸν Παῦλον.',
      'hoitines proselthontes tois archiereusi kai tois presbyterois eipon, Anathemati anethematisamen heautous, mēdenos geusasthai heōs hou apokteinōmen ton Paulon.',
      'The chief priests and elders are co-conspirators — the institution is now implicated. Josephus records the deep Sadducean-Sicarii collusion of this period.',
      'When religious leadership takes counsel with assassins, the institution has already forfeited its claim to speak for God.'),
  (15, 'Now therefore ye with the council signify to the chief captain that he bring him down unto you to morrow, as though ye would enquire something more perfectly concerning him: and we, or ever he come near, are ready to kill him.',
      'νῦν οὖν ὑμεῖς ἐμφανίσατε τῷ χιλιάρχῳ σὺν τῷ συνεδρίῳ, ὅπως αὔριον αὐτὸν καταγάγῃ πρὸς ὑμᾶς, ὡς μέλλοντας διαγινώσκειν ἀκριβέστερον τὰ περὶ αὐτοῦ· ἡμεῖς δέ, πρὸ τοῦ ἐγγίσαι αὐτόν, ἕτοιμοί ἐσμεν τοῦ ἀνελεῖν αὐτόν.',
      'nyn oun hymeis emphanisate tō chiliarchō syn tō synedriō, hopōs aurion auton katagagē pros hymas, hōs mellontas diaginōskein akribesteron ta peri autou; hēmeis de, pro tou engisai auton, hetoimoi esmen tou anelein auton.',
      'The plan: a forged request from the Sanhedrin to Lysias. Assassins will spring the ambush on the stairs between Antonia and the temple — the same stairs where Paul spoke in ch.22.',
      'Evil disguises itself in legal forms. The gospel''s enemies often borrow the language of careful inquiry while plotting murder in the next breath.'),
  (16, 'And when Paul''s sister''s son heard of their lying in wait, he went and entered into the castle, and told Paul.',
      'Ἀκούσας δὲ ὁ υἱὸς τῆς ἀδελφῆς Παύλου τὸ ἔνεδρον, παραγενόμενος καὶ εἰσελθὼν εἰς τὴν παρεμβολήν, ἀπήγγειλε τῷ Παύλῳ.',
      'Akousas de ho huios tēs adelphēs Paulou to enedron, paragenomenos kai eiselthōn eis tēn parembolēn, apēngeile tō Paulō.',
      'The only NT reference to Paul''s family — a sister and nephew living in Jerusalem. The youth overhears somewhere within the Jewish establishment — suggesting the family had connections.',
      'God places providential ears in unsuspected places. A young man''s overhearing becomes the hinge of an apostle''s life and a gospel''s journey.'),
  (17, 'Then Paul called one of the centurions unto him, and said, Bring this young man unto the chief captain: for he hath a certain thing to tell him.',
      'προσκαλεσάμενος δὲ ὁ Παῦλος ἕνα τῶν ἑκατοντάρχων ἔφη, Τὸν νεανίαν τοῦτον ἀπάγαγε πρὸς τὸν χιλίαρχον· ἔχει γὰρ τι ἀπαγγεῖλαι αὐτῷ.',
      'proskalesamenos de ho Paulos hena tōn hekatontarchōn ephē, Ton neanian touton apagage pros ton chiliarchon; echei gar ti apangeilai autō.',
      'Paul responds with lawful discretion, sending his nephew by proper channels. Trust in divine protection does not make the apostle careless of ordinary means.',
      'Divine assurance commissions practical action. Faith that expects deliverance also sends the messenger to the officer in charge.'),
  (18, 'So he took him, and brought him to the chief captain, and said, Paul the prisoner called me unto him, and prayed me to bring this young man unto thee, who hath something to say unto thee.',
      'Ὁ μὲν οὖν παραλαβὼν αὐτὸν ἤγαγε πρὸς τὸν χιλίαρχον, καί φησιν, Ὁ δέσμιος Παῦλος προσκαλεσάμενός με ἠρώτησε τοῦτον τὸν νεανίαν ἀγαγεῖν πρός σε, ἔχοντά τι λαλῆσαί σοι.',
      'Ho men oun paralabōn auton ēgage pros ton chiliarchon, kai phēsin, Ho desmios Paulos proskalesamenos me ērōtēse touton ton neanian agagein pros se, echonta ti lalēsai soi.',
      '"Paul the prisoner" (ho desmios Paulos) — the centurion''s matter-of-fact description that will become Paul''s self-designation (Eph 3:1; 4:1; Philem 1).',
      'The chains of the Lord''s servant are the jewels of his ministry. "Paul the prisoner" is a title he will treasure for Christ''s sake.'),
  (19, 'Then the chief captain took him by the hand, and went with him aside privately, and asked him, What is that thou hast to tell me?',
      'ἐπιλαβόμενος δὲ τῆς χειρὸς αὐτοῦ ὁ χιλίαρχος, καὶ ἀναχωρήσας κατ᾽ ἰδίαν ἐπυνθάνετο, Τί ἐστιν ὃ ἔχεις ἀπαγγεῖλαί μοι;',
      'epilabomenos de tēs cheiros autou ho chiliarchos, kai anachōrēsas kat idian epynthaneto, Ti estin ho echeis apangeilai moi?',
      'Lysias handles the youth with unexpected gentleness — taking him by the hand, withdrawing for a private hearing.',
      'God even softens pagan hearts to handle the testimony of children with dignity. Pastoral kindness can appear in uniformed hands.'),
  (20, 'And he said, The Jews have agreed to desire thee that thou wouldest bring down Paul to morrow into the council, as though they would enquire somewhat of him more perfectly.',
      'εἶπε δὲ ὅτι Οἱ Ἰουδαῖοι συνέθεντο τοῦ ἐρωτῆσαί σε, ὅπως αὔριον εἰς τὸ συνέδριον καταγάγῃς τὸν Παῦλον, ὡς μέλλοντές τι ἀκριβέστερον πυνθάνεσθαι περὶ αὐτοῦ.',
      'eipe de hoti Hoi Ioudaioi synethento tou erōtēsai se, hopōs aurion eis to synedrion katagagēs ton Paulon, hōs mellontes ti akribesteron pynthanesthai peri autou.',
      'The nephew lays out the conspiracy exactly as the plotters planned it — he has evidently overheard the whole scheme.',
      'God''s small witnesses can unmask large plots. A family member''s plain account saves an apostle''s life.'),
  (21, 'But do not thou yield unto them: for there lie in wait for him of them more than forty men, which have bound themselves with an oath, that they will neither eat nor drink till they have killed him: and now are they ready, looking for a promise from thee.',
      'σὺ οὖν μὴ πεισθῇς αὐτοῖς· ἐνεδρεύουσι γὰρ αὐτὸν ἐξ αὐτῶν ἄνδρες πλείους τεσσαράκοντα, οἵτινες ἀνεθεμάτισαν ἑαυτοὺς μήτε φαγεῖν μήτε πιεῖν ἕως οὗ ἀνέλωσιν αὐτόν· καὶ νῦν ἕτοιμοί εἰσι, προσδεχόμενοι τὴν ἀπὸ σοῦ ἐπαγγελίαν.',
      'sy oun mē peisthēs autois; enedreuousi gar auton ex autōn andres pleious tessarakonta, hoitines anethematisan heautous mēte phagein mēte piein heōs hou anelōsin auton; kai nyn hetoimoi eisi, prosdechomenoi tēn apo sou epangelian.',
      'The nephew warns Lysias not to grant the request; the ambushers are already in position, awaiting only Lysias''s promise.',
      'Evil is often exposed by its own urgency. Plots ripen only until a faithful word punctures them.'),
  (22, 'So the chief captain then let the young man depart, and charged him, See thou tell no man that thou hast shewed these things to me.',
      'Ὁ μὲν οὖν χιλίαρχος ἀπέλυσε τὸν νεανίαν, παραγγείλας μηδενὶ ἐκλαλῆσαι ὅτι ταῦτα ἐνεφάνισας πρός με.',
      'Ho men oun chiliarchos apelyse ton neanian, parangeilas mēdeni eklalēsai hoti tauta enephanisas pros me.',
      'Lysias protects his informant with operational discipline — the classic oath of silence given to a witness.',
      'God''s providences often travel with prudent silences. Not every deliverance is to be broadcast while it is unfolding.'),
  (23, 'And he called unto him two centurions, saying, Make ready two hundred soldiers to go to Caesarea, and horsemen threescore and ten, and spearmen two hundred, at the third hour of the night;',
      'Καὶ προσκαλεσάμενος δύο τινὰς τῶν ἑκατοντάρχων εἶπεν, Ἑτοιμάσατε στρατιώτας διακοσίους ὅπως πορευθῶσιν ἕως Καισαρείας, καὶ ἱππεῖς ἑβδομήκοντα, καὶ δεξιολάβους διακοσίους, ἀπὸ τρίτης ὥρας τῆς νυκτός·',
      'Kai proskalesamenos dyo tinas tōn hekatontarchōn eipen, Hetoimasate stratiōtas diakosious hopōs poreuthōsin heōs Kaisareias, kai hippeis hebdomēkonta, kai dexiolabous diakosious, apo tritēs hōras tēs nyktos;',
      '470 men for one prisoner — half the Jerusalem garrison. "Dexiolaboi" (spearmen) — literally "right-hand holders," probably light-armed javelinists. Third hour of the night = 9 p.m.',
      'The God who commanded "Be of good cheer, thou shalt bear witness at Rome" is happy to commission 470 Roman soldiers to keep the promise.'),
  (24, 'And provide them beasts, that they may set Paul on, and bring him safe unto Felix the governor.',
      'κτήνη τε παραστῆσαι, ἵνα ἐπιβιβάσαντες τὸν Παῦλον διασώσωσι πρὸς Φήλικα τὸν ἡγεμόνα.',
      'ktēnē te parastēsai, hina epibibasantes ton Paulon diasōsōsi pros Phēlika ton hēgemona.',
      'Ktēnē (plural) — mounts and spare horses. Marcus Antonius Felix, a freedman of Claudius, governed Judaea AD 52-60. Tacitus called him one who "with all cruelty and lust exercised the power of a king with the spirit of a slave" (Hist. 5.9).',
      'God''s deliverance is bodily and logistical. The apostle rides to his next platform on Roman mule-back under military escort.'),
  (25, 'And he wrote a letter after this manner:',
      'γράψας ἐπιστολὴν περιέχουσαν τὸν τύπον τοῦτον·',
      'grapsas epistolēn periechousan ton typon touton;',
      'Luke evidently obtained the letter text later at Caesarea. Such letters accompanied all prisoners transferred to higher courts (elogium).',
      'God''s historians record the documents of providence. The church''s history is also an archive of divine dealings in paper and ink.'),
  (26, 'Claudius Lysias unto the most excellent governor Felix sendeth greeting.',
      'Κλαύδιος Λυσίας τῷ κρατίστῳ ἡγεμόνι Φήλικι χαίρειν.',
      'Klaudios Lysias tō kratistō hēgemoni Phēliki chairein.',
      'We learn the tribune''s name: Claudius Lysias. "Kratistō" ("most excellent") is the honorific for equestrian-rank officials, addressed also to Theophilus (Luke 1:3).',
      'Historical names grant credibility. Luke''s Gospel and Acts both touch named officials whose existence is verifiable in imperial records.'),
  (27, 'This man was taken of the Jews, and should have been killed of them: then came I with an army, and rescued him, having understood that he was a Roman.',
      'Τὸν ἄνδρα τοῦτον συλληφθέντα ὑπὸ τῶν Ἰουδαίων, καὶ μέλλοντα ἀναιρεῖσθαι ὑπ᾽ αὐτῶν, ἐπιστὰς σὺν τῷ στρατεύματι ἐξειλόμην αὐτόν, μαθὼν ὅτι Ῥωμαῖός ἐστι.',
      'Ton andra touton syllēphthenta hypo tōn Ioudaiōn, kai mellonta anaireisthai hyp autōn, epistas syn tō strateumati exeilomēn auton, mathōn hoti Rhōmaios esti.',
      'Lysias airbrushes the sequence — he rescued Paul before learning he was a Roman (21:31-33), and had actually ordered him scourged (22:24-29). Official reports can bend the truth while preserving the form.',
      'Even in the empire''s paperwork God preserves His servant. Partial truths in human letters cannot derail the perfect plan of heaven.'),
  (28, 'And when I would have known the cause wherefore they accused him, I brought him forth into their council:',
      'βουλόμενος δὲ γνῶναι τὴν αἰτίαν δι᾽ ἣν ἐνεκάλουν αὐτῷ, κατήγαγον αὐτὸν εἰς τὸ συνέδριον αὐτῶν·',
      'boulomenos de gnōnai tēn aitian di hēn enekaloun autō, katēgagon auton eis to synedrion autōn;',
      'The narrative continues.',
      'The Lord directs the pen of pagan officials for His eternal purposes.'),
  (29, 'Whom I perceived to be accused of questions of their law, but to have nothing laid to his charge worthy of death or of bonds.',
      'ὃν εὗρον ἐγκαλούμενον περὶ ζητημάτων τοῦ νόμου αὐτῶν, μηδὲν δὲ ἄξιον θανάτου ἢ δεσμῶν ἔγκλημα ἔχοντα.',
      'hon heuron enkaloumenon peri zētēmatōn tou nomou autōn, mēden de axion thanatou ē desmōn enklēma echonta.',
      'Lysias''s verdict — a "religious dispute," not a capital crime. This becomes a recurring pattern: Roman officials find Christians innocent of political sedition (cf. 18:15; 25:25; 26:31).',
      'Pagan magistrates repeatedly declare Christianity innocent of the charges. Rome''s own records bear witness that the gospel is no threat to lawful order.'),
  (30, 'And when it was told me how that the Jews laid wait for the man, I sent straightway to thee, and gave commandment to his accusers also to say before thee what they had against him. Farewell.',
      'μηνυθείσης δέ μοι ἐπιβουλῆς εἰς τὸν ἄνδρα μέλλειν ἔσεσθαι ὑπὸ τῶν Ἰουδαίων, ἐξαυτῆς ἔπεμψα πρός σε, παραγγείλας καὶ τοῖς κατηγόροις λέγειν τὰ πρὸς αὐτὸν ἐπί σοῦ. Ἔρρωσο.',
      'mēnytheisēs de moi epiboulēs eis ton andra mellein esesthai hypo tōn Ioudaiōn, exautēs epempsa pros se, parangeilas kai tois katēgorois legein ta pros auton epi sou. Errōso.',
      '"Errōso" ("be strong") is the standard Roman letter farewell, like "Valete."',
      'Imperial correspondence carries kingdom purposes within it. The closing "Farewell" ends a letter that secures Paul''s passage to Rome.'),
  (31, 'Then the soldiers, as it was commanded them, took Paul, and brought him by night to Antipatris.',
      'Οἱ μὲν οὖν στρατιῶται, κατὰ τὸ διατεταγμένον αὐτοῖς, ἀναλαβόντες τὸν Παῦλον, ἤγαγον διὰ τῆς νυκτὸς εἰς τὴν Ἀντιπατρίδα.',
      'Hoi men oun stratiōtai, kata to diatetagmenon autois, analabontes ton Paulon, ēgagon dia tēs nyktos eis tēn Antipatrida.',
      'Antipatris (Herod''s fortress on the coastal plain, at modern Rosh Ha''ayin) was about 37 miles northwest of Jerusalem — a long night march on safer ground.',
      'God''s deliveries often travel by night. When the world sleeps, the Spirit moves His servants along the appointed road.'),
  (32, 'On the morrow they left the horsemen to go with him, and returned to the castle:',
      'Τῇ δὲ ἐπαύριον ἐάσαντες τοὺς ἱππεῖς πορεύεσθαι σὺν αὐτῷ, ὑπέστρεψαν εἰς τὴν παρεμβολήν·',
      'Tē de epaurion easantes tous hippeis poreuesthai syn autō, hypestrepsan eis tēn parembolēn;',
      'Beyond Antipatris the hostile Judean zone was passed. The 400 infantry return; the 70 cavalry continue the 25 miles to Caesarea.',
      'Danger ebbs as providence proves its escort. God measures the threat and sends the exact protection required.'),
  (33, 'Who, when they came to Caesarea, and delivered the epistle to the governor, presented Paul also before him.',
      'οἵτινες εἰσελθόντες εἰς τὴν Καισάρειαν, καὶ ἀναδόντες τὴν ἐπιστολὴν τῷ ἡγεμόνι, παρέστησαν καὶ τὸν Παῦλον αὐτῷ.',
      'hoitines eiselthontes eis tēn Kaisareian, kai anadontes tēn epistolēn tō hēgemoni, parestēsan kai ton Paulon autō.',
      'Paul stands before Felix in Caesarea — Roman capital of Judaea, the same city where he had stayed with Philip six weeks before.',
      'God completes what He begins. Every stage from Philip''s house to Herod''s praetorium unfolds under the same redemptive hand.'),
  (34, 'And when the governor had read the letter, he asked of what province he was. And when he understood that he was of Cilicia;',
      'Ἀναγνοὺς δὲ ὁ ἡγεμών, καὶ ἐπερωτήσας ἐκ ποίας ἐπαρχίας ἐστί, καὶ πυθόμενος ὅτι ἀπὸ Κιλικίας,',
      'Anagnous de ho hēgemōn, kai eperōtēsas ek poias eparchias esti, kai pythomenos hoti apo Kilikias,',
      'Roman law assigned jurisdiction by the defendant''s province of origin. Cilicia was then attached to the Syrian governorship, but Felix chooses to hear the case himself as the case arose in his jurisdiction.',
      'The empire''s legal machinery serves God''s appointed stage. Paul''s province of origin becomes providentially irrelevant to the hearing.'),
  (35, 'I will hear thee, said he, when thine accusers are also come. And he commanded him to be kept in Herod''s judgment hall.',
      'Διακούσομαί σου, ἔφη, ὅταν καὶ οἱ κατήγοροί σου παραγένωνται. Ἐκέλευσέ τε αὐτὸν ἐν τῷ πραιτωρίῳ τοῦ Ἡρώδου φυλάσσεσθαι.',
      'Diakousomai sou, ephē, hotan kai hoi katēgoroi sou paragenōntai. Ekeleuse te auton en tō praitōriō tou Hērōdou phylassesthai.',
      '"Herod''s judgment hall" (praitōrion) was the palace built by Herod the Great in Caesarea, now the provincial governor''s residence. Paul will lodge here — in comfortable imprisonment — for the next two years.',
      'God''s providence gives the apostle a palace for a cell. The places of pagan power become stations of gospel witness.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Acts' AND c.chapter_number = 23
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'ἀτενίσας', 'atenisas', 'G816', 'Having gazed intently — Paul''s steady apostolic look.', 1),
  (1, 'πεπολίτευμαι', 'pepoliteumai', 'G4176', 'Have conducted myself as a citizen — of God''s kingdom.', 2),
  (1, 'συνειδήσει', 'syneidēsei', 'G4893', 'Conscience — moral consciousness before God.', 3),
  (3, 'τοῖχε κεκονιαμένε', 'toiche kekoniamene', 'G5109/G2867', 'Whited wall — painted façade hiding decay (Ezek 13:10-11).', 4),
  (5, 'ἄρχοντα', 'archonta', 'G758', 'Ruler — civil/religious authority (Exod 22:28).', 5),
  (6, 'ἐλπίδος καὶ ἀναστάσεως', 'elpidos kai anastaseōs', 'G1680/G386', 'Hope and resurrection — Paul''s theological flag in court.', 6),
  (7, 'στάσις', 'stasis', 'G4714', 'Dissension, faction — theological division.', 7),
  (8, 'ἀνάστασιν', 'anastasin', 'G386', 'Resurrection — Sadducee denial, Pharisee confession.', 8),
  (9, 'θεομαχῶμεν', 'theomachōmen', 'G2313', 'Let us not fight against God — cf. 5:39, Gamaliel.', 9),
  (10, 'διασπασθῇ', 'diaspasthē', 'G1288', 'Be torn apart, pulled in pieces — mob danger.', 10),
  (11, 'θάρσει', 'tharsei', 'G2293', 'Be of good cheer — Jesus-word of courage (Matt 9:2; 14:27).', 11),
  (11, 'διεμαρτύρω', 'diemartyrō', 'G1263', 'Didst testify solemnly — formal witness-bearing.', 12),
  (11, 'δεῖ', 'dei', 'G1163', 'It is necessary — divine necessity (dei for Rome).', 13),
  (12, 'ἀνεθεμάτισαν', 'anethematisan', 'G332', 'Placed themselves under a curse (cherem).', 14),
  (13, 'συνωμοσίαν', 'synōmosian', 'G4945', 'Conspiracy, sworn band — pre-meditated terror cell.', 15),
  (15, 'διαγινώσκειν ἀκριβέστερον', 'diaginōskein akribesteron', 'G1231/G199', 'To determine more accurately — legal pretext.', 16),
  (16, 'ἔνεδρον', 'enedron', 'G1749', 'Ambush, lying in wait — plot against life.', 17),
  (18, 'δέσμιος', 'desmios', 'G1198', 'Prisoner — Paul''s cherished title in later epistles.', 18),
  (23, 'δεξιολάβους', 'dexiolabous', 'G1187', 'Spearmen — "right-hand grasping" javelin throwers.', 19),
  (23, 'τρίτης ὥρας τῆς νυκτός', 'tritēs hōras tēs nyktos', 'G5154/G5610/G3571', 'Third hour of the night — c. 9 p.m. departure.', 20),
  (24, 'κτήνη', 'ktēnē', 'G2934', 'Beasts — pack animals/mounts for transport.', 21),
  (24, 'διασώσωσι', 'diasōsōsi', 'G1295', 'Bring safely through — full deliverance.', 22),
  (24, 'Φήλικα', 'Phēlika', 'G5344', 'Felix — procurator of Judaea AD 52-60.', 23),
  (26, 'κρατίστῳ', 'kratistō', 'G2903', 'Most excellent — equestrian honorific (cf. Luke 1:3).', 24),
  (26, 'χαίρειν', 'chairein', 'G5463', 'Greetings — standard Hellenistic letter opening.', 25),
  (29, 'ζητημάτων τοῦ νόμου', 'zētēmatōn tou nomou', 'G2213/G3551', 'Questions of the law — Roman dismissal of theological disputes.', 26),
  (29, 'ἔγκλημα', 'enklēma', 'G1462', 'Formal accusation, charge.', 27),
  (30, 'Ἔρρωσο', 'Errōso', 'G4517', 'Farewell — Roman epistolary closing.', 28),
  (31, 'Ἀντιπατρίδα', 'Antipatrida', 'G494', 'Antipatris — Herodian fortress on the coastal plain.', 29),
  (33, 'ἀναδόντες', 'anadontes', 'G325', 'Delivered up — handed over the letter.', 30),
  (35, 'πραιτωρίῳ', 'praitōriō', 'G4232', 'Praetorium — governor''s palace/headquarters.', 31)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Acts' AND c.chapter_number = 23 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

